require('dotenv').config();
const { CosmosClient } = require("@azure/cosmosdb");

// Initialize the Cosmos DB client
const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);

// HTTP trigger function processing large datasets from Cosmos DB
exports.processLargeData = async function (context, req) {
    const dbName = process.env.COSMOS_DB_DATABASE_NAME;
    const containerName = process.env.COSMOS_DB_CONTAINER_NAME;

    // Create a new database and container if not already exist
    const { databaseId } = await cosmosClient.databases.createIfNotExists({ databaseName: dbName });
    const { containerId } = await cosmosClient.containers.createIfNotExists({
        databaseName: databaseId,
        containerDefinition: { id: containerName, partitionKeyPath: "/id" },
    });

    // Create a new item in Cosmos DB for storing the function's status
    const { container } = await cosmosClient.container(containerId);
    const { resource } = await container.items.create({ id: "processingStatus", data: { processing: true } });

    // Your custom large dataset processing code here
    // ...

    // Update the item in Cosmos DB to mark the function as completed
    const response = await container.item(resource._self).replace({ data: { processing: false } });
    context.log(`Processing completed with result: ${JSON.stringify(response)}`);
};